import java.io.*;
import java.util.*;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userName = scanner.nextLine();

        System.out.println("Hello, " + encodeHtml(userName) + "!"); // Encode user input

        scanner.close();
    }

    private static String encodeHtml(String input) {
        StringBuilder builder = new StringBuilder();

        for (char c : input.toCharArray()) {
            switch (c) {
                case '&':
                    builder.append("&amp;");
                    break;
                case '<':
                    builder.append("&lt;");
                    break;
                case '>':
                    builder.append("&gt;");
                    break;
                case '"':
                    builder.append("&quot;");
                    break;
                default:
                    builder.append(c);
            }
        }

        return builder.toString();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
